const employees = [
  { id: 1, name: 'John', department: 'Sales', salary: 50000 },
  { id: 2, name: 'Jane', department: 'Marketing', salary: 60000 },
  { id: 3, name: 'Sam', department: 'IT', salary: 70000 }
];

const modifiedEmployees = employees.map(employee => {
  return {
    ...employee,
    name: employee.name.toUpperCase(),
    department: employee.department.toLowerCase(),
    salary: employee.salary * 1.1 // Increase the salary by 10%
  };
});

console.log(modifiedEmployees);
